"use client";

import {
  useState,
  useCallback,
  type RefObject,
  type KeyboardEvent,
} from "react";
import { resolveDirectionKeys, dispatchNavigationKey } from "./internal/navigation-dispatch.js";
import {
  containsActiveElement,
  getFocusedNavigationValue,
  getNavigationItems,
  type NavigationItemType,
} from "../utils/navigation-items.js";

export type NavigationRole = NavigationItemType;

export interface UseNavigationOptions {
  containerRef: RefObject<HTMLElement | null>;
  role: NavigationRole;
  highlighted?: string | null;
  defaultHighlighted?: string | null;
  onHighlightChange?: (value: string) => void;
  onSelect?: (value: string, event: globalThis.KeyboardEvent) => void;
  onEnter?: (value: string, event: globalThis.KeyboardEvent) => void;
  wrap?: boolean;
  enabled?: boolean;
  preventDefault?: boolean;
  onNavigationBoundaryReached?: (direction: "previous" | "next") => void;
  upKeys?: readonly string[];
  downKeys?: readonly string[];
  orientation?: "vertical" | "horizontal";
  skipDisabled?: boolean;
  moveFocus?: boolean;
  scopeToContainer?: boolean;
  ownerSelector?: string | null;
}

export interface UseNavigationReturn {
  highlighted: string | null;
  isHighlighted: (value: string) => boolean;
  highlight: (value: string) => void;
  onKeyDown: (event: KeyboardEvent) => void;
}

interface UseNavigationCoreReturn {
  highlighted: string | null;
  isHighlighted: (value: string) => boolean;
  highlight: (value: string) => void;
  move: (delta: 1 | -1) => void;
  focusIndex: (index: number) => void;
  handleSelect: (event: globalThis.KeyboardEvent) => void;
  handleEnter: (event: globalThis.KeyboardEvent) => void;
  getElements: () => HTMLElement[];
}

function queryNavigationElements(
  containerRef: RefObject<HTMLElement | null>,
  role: NavigationRole,
  skipDisabled: boolean,
  scopeToContainer: boolean,
  ownerSelector: string | null | undefined,
): HTMLElement[] {
  return getNavigationItems(containerRef.current, {
    type: role,
    skipDisabled,
    scopeToContainer,
    ownerSelector,
  });
}

function wrapIndex(index: number, length: number, wrap: boolean): number | null {
  if (index < 0) return wrap ? length - 1 : null;
  if (index >= length) return wrap ? 0 : null;
  return index;
}

export function useNavigationCore({
  containerRef,
  role,
  highlighted: controlledHighlighted,
  defaultHighlighted = null,
  onSelect,
  onEnter,
  onHighlightChange,
  wrap = true,
  onNavigationBoundaryReached,
  skipDisabled = true,
  moveFocus = false,
  scopeToContainer = true,
  ownerSelector,
}: UseNavigationOptions): UseNavigationCoreReturn {
  const [internalHighlighted, setInternalHighlighted] = useState<string | null>(defaultHighlighted);
  const isControlled = controlledHighlighted !== undefined;
  const highlighted = isControlled ? controlledHighlighted ?? null : internalHighlighted;

  const setFocusedValue = useCallback((nextValue: string) => {
    if (!isControlled) setInternalHighlighted(nextValue);
    onHighlightChange?.(nextValue);
  }, [isControlled, onHighlightChange]);

  const getElements = useCallback(
    () => queryNavigationElements(containerRef, role, skipDisabled, scopeToContainer, ownerSelector),
    [containerRef, role, skipDisabled, scopeToContainer, ownerSelector],
  );

  const getFocusedIndex = useCallback((): number => {
    const elements = getElements();
    if (elements.length === 0) return -1;

    const focusedIndex = elements.findIndex(containsActiveElement);
    if (focusedIndex >= 0) return focusedIndex;

    if (highlighted !== null) {
      const index = elements.findIndex((el) => el.dataset.value === highlighted);
      if (index >= 0) return index;
    }

    return -1;
  }, [getElements, highlighted]);

  const getCurrentValue = useCallback((): string | null => {
    const focusedValue = getFocusedNavigationValue(containerRef.current, {
      type: role,
      skipDisabled,
      scopeToContainer,
      ownerSelector,
    });
    if (focusedValue !== null) return focusedValue;

    const elements = getElements();

    if (highlighted !== null) {
      return elements.some((el) => el.dataset.value === highlighted) ? highlighted : null;
    }

    return null;
  }, [containerRef, getElements, highlighted, ownerSelector, role, scopeToContainer, skipDisabled]);

  const focusIndex = useCallback((index: number) => {
    const elements = getElements();
    const el = elements[index];
    if (!el) return;
    const nextValue = el.dataset.value;
    if (nextValue === undefined) return;

    el.scrollIntoView?.({ block: "nearest" });
    if (moveFocus) el.focus();
    setFocusedValue(nextValue);
  }, [getElements, moveFocus, setFocusedValue]);

  const move = useCallback((delta: 1 | -1) => {
    const elements = getElements();
    if (elements.length === 0) return;

    const current = getFocusedIndex();
    const rawNext = current + delta;
    const next = wrapIndex(rawNext, elements.length, wrap);
    if (next === null) {
      onNavigationBoundaryReached?.(delta < 0 ? "previous" : "next");
      return;
    }

    focusIndex(next);
  }, [focusIndex, getElements, getFocusedIndex, onNavigationBoundaryReached, wrap]);

  const handleSelect = useCallback((event: globalThis.KeyboardEvent) => {
    const currentValue = getCurrentValue();
    if (currentValue !== null) onSelect?.(currentValue, event);
  }, [getCurrentValue, onSelect]);

  const handleEnter = useCallback((event: globalThis.KeyboardEvent) => {
    const currentValue = getCurrentValue();
    if (currentValue === null) return;
    if (onEnter) onEnter(currentValue, event);
    else onSelect?.(currentValue, event);
  }, [getCurrentValue, onEnter, onSelect]);

  const isHighlighted = useCallback((v: string) => highlighted === v, [highlighted]);
  const highlight = useCallback((v: string) => setFocusedValue(v), [setFocusedValue]);

  return { highlighted, isHighlighted, highlight, move, focusIndex, handleSelect, handleEnter, getElements };
}

export function useNavigation(options: UseNavigationOptions): UseNavigationReturn {
  const {
    enabled = true,
    preventDefault = true,
    orientation = "vertical",
    upKeys,
    downKeys,
    moveFocus = false,
    onEnter,
    onSelect,
  } = options;

  const { resolvedUpKeys, resolvedDownKeys } = resolveDirectionKeys(orientation, upKeys, downKeys);

  const { highlighted, isHighlighted, highlight, move, focusIndex, handleSelect, handleEnter, getElements } =
    useNavigationCore(options);
  const handlesEnter = !moveFocus || Boolean(onEnter || onSelect);
  const handlesSpace = !moveFocus || Boolean(onSelect);

  const onKeyDown = useCallback((event: KeyboardEvent) => {
    if (!enabled) return;

    const key = event.key;
    const isMoveKey = resolvedUpKeys.includes(key) || resolvedDownKeys.includes(key);
    const isSpecialKey =
      key === "Home"
      || key === "End"
      || (key === "Enter" && handlesEnter)
      || (key === " " && handlesSpace);
    if (!isMoveKey && !isSpecialKey) return;

    if (preventDefault) event.preventDefault();

    dispatchNavigationKey(key, {
      resolvedUpKeys,
      resolvedDownKeys,
      move,
      focusIndex,
      handleSelect: handlesSpace ? (e) => handleSelect(e) : undefined,
      handleEnter: handlesEnter ? (e) => handleEnter(e) : undefined,
      total: getElements().length,
      nativeEvent: event.nativeEvent,
    });
  }, [
    enabled,
    resolvedUpKeys,
    resolvedDownKeys,
    preventDefault,
    handlesEnter,
    handlesSpace,
    move,
    focusIndex,
    handleSelect,
    handleEnter,
    getElements,
  ]);

  return { highlighted, isHighlighted, highlight, onKeyDown };
}

const VERTICAL_UP_KEYS = ["ArrowUp"] as const;
const VERTICAL_DOWN_KEYS = ["ArrowDown"] as const;
const HORIZONTAL_UP_KEYS = ["ArrowLeft"] as const;
const HORIZONTAL_DOWN_KEYS = ["ArrowRight"] as const;

export function resolveDirectionKeys(
  orientation: "vertical" | "horizontal",
  upKeys?: readonly string[],
  downKeys?: readonly string[],
): { resolvedUpKeys: readonly string[]; resolvedDownKeys: readonly string[] } {
  return {
    resolvedUpKeys: upKeys ?? (orientation === "vertical" ? VERTICAL_UP_KEYS : HORIZONTAL_UP_KEYS),
    resolvedDownKeys: downKeys ?? (orientation === "vertical" ? VERTICAL_DOWN_KEYS : HORIZONTAL_DOWN_KEYS),
  };
}

export function dispatchNavigationKey(
  key: string,
  ctx: {
    resolvedUpKeys: readonly string[];
    resolvedDownKeys: readonly string[];
    move: (dir: 1 | -1) => void;
    focusIndex: (index: number) => void;
    handleSelect?: (event: globalThis.KeyboardEvent) => void;
    handleEnter?: (event: globalThis.KeyboardEvent) => void;
    total: number;
    nativeEvent: globalThis.KeyboardEvent;
  },
): boolean {
  if (ctx.resolvedUpKeys.includes(key)) {
    ctx.move(-1);
    return true;
  }

  if (ctx.resolvedDownKeys.includes(key)) {
    ctx.move(1);
    return true;
  }

  switch (key) {
    case "Home":
      ctx.focusIndex(0);
      return true;
    case "End": {
      if (ctx.total > 0) ctx.focusIndex(ctx.total - 1);
      return true;
    }
    case "Enter":
      ctx.handleEnter?.(ctx.nativeEvent);
      return true;
    case " ":
      ctx.handleSelect?.(ctx.nativeEvent);
      return true;
  }

  return false;
}

export const NAVIGATION_ITEM_ATTRIBUTE = "data-diffgazer-navigation-item";

const FOCUSABLE_SELECTOR = [
  "a[href]",
  "area[href]",
  "button:not([disabled])",
  'input:not([type="hidden"]):not([disabled])',
  "select:not([disabled])",
  "textarea:not([disabled])",
  "iframe",
  "object",
  "embed",
  "audio[controls]",
  "video[controls]",
  '[contenteditable]:not([contenteditable="false"])',
  '[tabindex]:not([tabindex="-1"]):not([disabled])',
].join(",");

export type NavigationItemType =
  | "radio"
  | "checkbox"
  | "option"
  | "menuitem"
  | "menuitemradio"
  | "button"
  | "tab";

export interface NavigationItemQuery {
  type: NavigationItemType;
  skipDisabled?: boolean;
  scopeToContainer?: boolean;
  ownerSelector?: string | null;
}

function disabledSelector(skipDisabled: boolean): string {
  return skipDisabled
    ? ':not([aria-disabled="true"]):not([data-disabled]):not(:disabled)'
    : "";
}

function findElements(container: HTMLElement, selector: string): HTMLElement[] {
  return Array.from(container.querySelectorAll<HTMLElement>(selector));
}

function queryFirstMatchingGroup(
  container: HTMLElement,
  selectors: string[],
  filter?: (element: HTMLElement) => boolean,
): HTMLElement[] {
  for (const selector of selectors) {
    const elements = filter
      ? findElements(container, selector).filter(filter)
      : findElements(container, selector);
    if (elements.length > 0) return elements;
  }
  return [];
}

function matchesNavigationDataContract(element: HTMLElement, type: NavigationItemType): boolean {
  const explicitType = element.getAttribute(NAVIGATION_ITEM_ATTRIBUTE);
  return explicitType === null || explicitType === "" || explicitType === "true" || explicitType === type;
}

function buildNavigationSelectors(
  type: NavigationItemType,
  skipDisabled: boolean,
): string[] {
  const disabled = disabledSelector(skipDisabled);
  const dataContractSelectors = [
    `[${NAVIGATION_ITEM_ATTRIBUTE}="${type}"][data-value]${disabled}`,
    `[${NAVIGATION_ITEM_ATTRIBUTE}="true"][data-value]${disabled}`,
    `[${NAVIGATION_ITEM_ATTRIBUTE}=""][data-value]${disabled}`,
    `[${NAVIGATION_ITEM_ATTRIBUTE}][data-value]${disabled}`,
  ];
  const nativeRoleSelectors: Partial<Record<NavigationItemType, string[]>> = {
    button: [`button[data-value]${disabled}`],
    checkbox: [`input[type="checkbox"][data-value]${disabled}`],
    radio: [`input[type="radio"][data-value]${disabled}`],
  };

  return [
    dataContractSelectors.join(","),
    `[role="${type}"][data-value]${disabled}`,
    ...(nativeRoleSelectors[type] ?? []),
    `[role="${type}"]${disabled}`,
  ];
}

function ownerSelectorForType(type: NavigationItemType): string | null {
  switch (type) {
    case "radio":
      return '[role="radiogroup"]';
    case "checkbox":
      return '[role="group"]';
    case "option":
      return '[role="listbox"]';
    case "menuitem":
    case "menuitemradio":
      return '[role="menu"]';
    case "tab":
      return '[role="tablist"]';
    case "button":
      return null;
  }
}

function isOwnedByContainer(
  element: HTMLElement,
  container: HTMLElement,
  query: NavigationItemQuery,
) {
  if (query.scopeToContainer === false) return true;

  if (query.ownerSelector !== undefined) {
    if (query.ownerSelector === null) return true;
    const owner = element.closest(query.ownerSelector);
    return owner === null || owner === container;
  }

  const ownerSelector = ownerSelectorForType(query.type);
  if (!ownerSelector) return true;

  const owner = element.closest(ownerSelector);
  return owner === null || owner === container;
}

export function getNavigationItems(
  container: HTMLElement | null,
  query: NavigationItemQuery,
): HTMLElement[] {
  if (!container) return [];

  return queryFirstMatchingGroup(
    container,
    buildNavigationSelectors(query.type, query.skipDisabled ?? true),
    (element) => matchesNavigationDataContract(element, query.type)
      && isOwnedByContainer(element, container, query),
  );
}

export function findNavigationItemByValue(
  container: HTMLElement | null,
  query: NavigationItemQuery & { value: string },
): HTMLElement | null {
  return getNavigationItems(container, query).find((element) => element.dataset.value === query.value) ?? null;
}

export function getNavigationItemProps(
  type: NavigationItemType,
  value: string,
): {
  "data-diffgazer-navigation-item": NavigationItemType;
  "data-value": string;
} {
  return {
    [NAVIGATION_ITEM_ATTRIBUTE]: type,
    "data-value": value,
  };
}

export function containsActiveElement(element: HTMLElement): boolean {
  const activeElement = element.ownerDocument.activeElement;
  const View = element.ownerDocument.defaultView;
  return Boolean(View && activeElement instanceof View.HTMLElement && element.contains(activeElement));
}

export function getFocusedNavigationValue(
  container: HTMLElement | null,
  query: NavigationItemQuery,
): string | null {
  const focusedItem = getNavigationItems(container, query).find(containsActiveElement);
  return focusedItem?.dataset.value ?? null;
}

export function focusNavigationItem(
  container: HTMLElement | null,
  query: NavigationItemQuery & {
    value: string;
    fallback?: "first" | "last" | "none";
    preventScroll?: boolean;
  },
): string | null {
  const items = getNavigationItems(container, query);
  const target =
    items.find((element) => element.dataset.value === query.value) ??
    (query.fallback === "first" ? items[0] : undefined) ??
    (query.fallback === "last" ? items.at(-1) : undefined) ??
    null;

  if (!target || target.dataset.value === undefined) return null;

  target.focus({ preventScroll: query.preventScroll });
  return target.dataset.value;
}

export function getFocusableElements(container: HTMLElement | null): HTMLElement[] {
  if (!container) return [];
  return Array.from(container.querySelectorAll<HTMLElement>(FOCUSABLE_SELECTOR));
}

export type VerticalDirection = "up" | "down";
export type BoundaryDirection = "previous" | "next";

export function getVerticalArrowDirection(key: string): VerticalDirection | null {
  if (key === "ArrowUp") return "up";
  if (key === "ArrowDown") return "down";
  return null;
}

export function toVerticalBoundaryDirection(direction: BoundaryDirection): VerticalDirection;
export function toVerticalBoundaryDirection(direction: BoundaryDirection, key: string): VerticalDirection | null;
export function toVerticalBoundaryDirection(direction: BoundaryDirection, key?: string): VerticalDirection | null {
  if (key !== undefined && getVerticalArrowDirection(key) === null) return null;
  return direction === "previous" ? "up" : "down";
}
